import{_ as e,o as a,c as l,a2 as o}from"./chunks/framework.BQ1gajhD.js";const q=JSON.parse('{"title":"法轮殿","description":"","frontmatter":{},"headers":[],"relativePath":"religion/yonghegong/falun-dian.md","filePath":"religion/yonghegong/falun-dian.md","lastUpdated":1784720050000}'),r={name:"religion/yonghegong/falun-dian.md"};function i(n,t,d,h,s,g){return a(),l("div",null,[...t[0]||(t[0]=[o('<h1 id="法轮殿" tabindex="-1">法轮殿 <a class="header-anchor" href="#法轮殿" aria-label="Permalink to &quot;法轮殿&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1782915763074-87f3c2c62fc1?w=1200&amp;q=80" alt="法轮殿藏式殿宇"></p><blockquote><p>&quot;殿顶五塔镏金，殿中罗汉成山——藏汉合璧的法轮殿，是雍和宫法事最盛之处，也是宗喀巴大师在京城的精神道场。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>法轮殿是雍和宫僧众诵经礼佛、举行大型法事的主殿，也是全寺藏式风格最鲜明的建筑。殿名取&quot;法轮常转&quot;之意——佛法如轮，辗转不息，摧破烦恼，普利有情。在雍亲王府时期，此处相传为福晋（雍亲王嫡福晋，即后来的孝敬宪皇后）的内寝院落；改寺之后扩建为大经堂，成为蒙藏学僧云集、法会经声不断的佛学中心。</p><p>殿内正中供奉藏传佛教格鲁派创始人宗喀巴大师的巨型铜像，大师背后陈设举世闻名的&quot;五百罗汉山&quot;——以整块紫檀木雕成山峦，五百尊金属罗汉散布其间，与万福阁白檀弥勒、金丝楠木佛龛并称&quot;雍和宫三绝&quot;。</p><h2 id="建筑与景观" tabindex="-1">建筑与景观 <a class="header-anchor" href="#建筑与景观" aria-label="Permalink to &quot;建筑与景观&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">规格与内容</th></tr></thead><tbody><tr><td style="text-align:left;">平面形制</td><td style="text-align:left;">十字形平面，藏汉合璧：汉式殿堂之上加藏式平顶与天窗</td></tr><tr><td style="text-align:left;">屋顶</td><td style="text-align:left;">黄琉璃瓦屋面，设五座镏金藏式小宝塔</td></tr><tr><td style="text-align:left;">殿内主供</td><td style="text-align:left;">宗喀巴大师铜像，高约6.1米，鎏金庄严</td></tr><tr><td style="text-align:left;">大师背后</td><td style="text-align:left;">五百罗汉山（紫檀木雕山 + 五百尊罗汉）</td></tr><tr><td style="text-align:left;">殿内陈设</td><td style="text-align:left;">坛城（曼荼罗）、经卷、法器等</td></tr></tbody></table><p>法轮殿外观为汉式大殿，殿顶却突起藏式平顶天窗，天窗之上矗立五座镏金小塔——五塔象征须弥山五形与四大部洲，也对应格鲁派尊崇的五方佛。汉地的大屋顶与藏式的金塔共处一殿，正是雍和宫&quot;汉藏一家&quot;最直观的建筑宣言。</p><h3 id="宗喀巴大师像" tabindex="-1">宗喀巴大师像 <a class="header-anchor" href="#宗喀巴大师像" aria-label="Permalink to &quot;宗喀巴大师像&quot;">​</a></h3><p>宗喀巴（1357—1419）是藏传佛教格鲁派（黄教）的创始人，第一世达赖喇嘛与第一世班禅额尔德尼皆出其门下。殿内铜像高约6.1米，大师头戴黄色尖顶僧帽，双手结转法轮印，左右各出一茎莲花，分托经箧与宝剑——寓意智慧如剑断惑、经教如灯照世。像前设有讲经法座，昔日大法会期间，蒙藏高僧即在此升座说法。</p><h3 id="五百罗汉山" tabindex="-1">五百罗汉山 <a class="header-anchor" href="#五百罗汉山" aria-label="Permalink to &quot;五百罗汉山&quot;">​</a></h3><p>五百罗汉山陈设于宗喀巴大师像背后，以一整块紫檀木（一说红木）雕成普陀洛伽山景：峰峦起伏、洞壑幽深，松柏亭塔错落其间；五百尊罗汉以金、银、铜、铁、锡五金铸成，或坐或立，或降龙或伏虎，或诵经或禅定，散布于山石之间，无一雷同。此山为乾隆年间雕造，工程浩大，是清代木雕与铸造工艺的巅峰之作。20世纪初庚子之变及此后动荡中，部分罗汉散佚损毁，现存已不足五百之数，更觉弥足珍贵。</p><h3 id="坛城-曼荼罗" tabindex="-1">坛城（曼荼罗） <a class="header-anchor" href="#坛城-曼荼罗" aria-label="Permalink to &quot;坛城（曼荼罗）&quot;">​</a></h3><p>殿内陈设有坛城（梵文 Mandala，曼荼罗），即密宗观修用的宇宙坛场模型：方形坛城之外设圆形护轮，中央主尊安住，四方四佛、八方菩萨各依方位排列，象征佛国净土的完整秩序。僧人修法时观想坛城，即是&quot;入佛国土&quot;的修持法门。坛城结构严谨、毫厘不差，是藏传佛教建筑与数理观念的浓缩。</p><h3 id="雍和宫三绝" tabindex="-1">&quot;雍和宫三绝&quot; <a class="header-anchor" href="#雍和宫三绝" aria-label="Permalink to &quot;&quot;雍和宫三绝&quot;&quot;">​</a></h3><p>法轮殿的五百罗汉山，与万福阁白檀木大佛、照佛楼檀香木佛龛并称&quot;雍和宫三绝&quot;：</p><table tabindex="0"><thead><tr><th style="text-align:left;">宝物</th><th style="text-align:left;">所在</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">五百罗汉山</td><td style="text-align:left;">法轮殿</td><td style="text-align:left;">整块紫檀木雕山景 + 五金铸造五百罗汉</td></tr><tr><td style="text-align:left;">白檀木大佛</td><td style="text-align:left;">万福阁</td><td style="text-align:left;">26米独木弥勒立像，吉尼斯世界纪录</td></tr><tr><td style="text-align:left;">檀香木佛龛</td><td style="text-align:left;">照佛楼</td><td style="text-align:left;">整块檀香木雕佛龛，透雕九龙盘旋</td></tr></tbody></table><p>三绝皆为&quot;一木一器&quot;的极致之作，集中在寺院最北三进院落，建议连贯参观。</p><h2 id="历史故事" tabindex="-1">历史故事 <a class="header-anchor" href="#历史故事" aria-label="Permalink to &quot;历史故事&quot;">​</a></h2><h3 id="福晋内寝变经堂" tabindex="-1">福晋内寝变经堂 <a class="header-anchor" href="#福晋内寝变经堂" aria-label="Permalink to &quot;福晋内寝变经堂&quot;">​</a></h3><p>相传法轮殿一带原为雍亲王府福晋的起居内寝。1744年改寺，王府最私密的内院被改建为最开放的经堂——僧侣日诵、大法会、跳布扎（打鬼）法事皆在此举行。从闺阁到法堂，空间的转身，恰是雍和宫&quot;舍家为寺&quot;的缩影。</p><h3 id="罗汉山的沧桑" tabindex="-1">罗汉山的沧桑 <a class="header-anchor" href="#罗汉山的沧桑" aria-label="Permalink to &quot;罗汉山的沧桑&quot;">​</a></h3><p>五百罗汉山雕成之后，曾完好陈列两百余年。清末民初战乱频仍，罗汉屡遭散失，山石亦有残损。所幸主体紫檀山景与大部分罗汉仍存，今日所见虽不足五百之数，其规模与工艺依然冠绝京华。</p><h3 id="岁末-打鬼-与正月祈愿" tabindex="-1">岁末&quot;打鬼&quot;与正月祈愿 <a class="header-anchor" href="#岁末-打鬼-与正月祈愿" aria-label="Permalink to &quot;岁末&quot;打鬼&quot;与正月祈愿&quot;">​</a></h3><p>法轮殿是雍和宫法事活动的中心。清代定制，每年岁末寺院举行&quot;打鬼&quot;（跳布扎，即藏传佛教羌姆法舞）法会：僧人头戴护法神面具，身着彩衣，在鼓钹诵经声中起舞，寓意驱除邪魔、迎祥纳福，届时王公大臣、蒙藏僧俗云集观礼，为京师一大盛况。正月新春又有祈福法会，诵经祝祷国泰民安。这一传统在今天的雍和宫仍以不同形式延续，法轮殿的经声梵呗从未真正断绝。</p><h2 id="必看亮点" tabindex="-1">必看亮点 <a class="header-anchor" href="#必看亮点" aria-label="Permalink to &quot;必看亮点&quot;">​</a></h2><ul><li><strong>藏汉合璧建筑</strong>：十字形平面、汉顶藏窗、五座镏金小塔，全寺建筑融合度最高的一殿。</li><li><strong>宗喀巴大师铜像</strong>：高约6.1米的鎏金巨像，京城供奉宗喀巴最重要的道场。</li><li><strong>五百罗汉山</strong>：&quot;雍和宫三绝&quot;之一，紫檀雕山与五金罗汉的旷世组合。</li><li><strong>坛城陈设</strong>：立体曼荼罗展现佛教宇宙观，密法艺术的精华。</li><li><strong>法会现场</strong>：若有缘逢大法会，可闻经声梵呗，感受活态的宗教传承。</li></ul><h2 id="参观贴士" tabindex="-1">参观贴士 <a class="header-anchor" href="#参观贴士" aria-label="Permalink to &quot;参观贴士&quot;">​</a></h2><ul><li>罗汉山体量庞大、细节繁复，建议预留时间逐区细观罗汉姿态。</li><li>殿内光线较暗且禁止拍照，可入殿后先静立片刻待眼睛适应。</li><li>瞻仰宗喀巴大师像时，留意其尖顶黄帽与肩头莲经、莲剑的标识。</li><li>殿为诵经重地，请绕行礼让僧人，勿阻挡法座与经堂通道。</li></ul><hr><p><strong>📍 位置</strong>：雍和宫中轴线第五进院落，永佑殿以北 <strong>⏱️ 建议游览</strong>：20-30分钟 <strong>🔗 返回</strong>：<a href="/beijing-travel-guide/religion/yonghegong/">雍和宫概览</a></p><p><strong>⬅️ 上一殿</strong>：<a href="/beijing-travel-guide/religion/yonghegong/yongyou-dian.html">永佑殿</a> ｜ <strong>➡️ 下一殿</strong>：<a href="/beijing-travel-guide/religion/yonghegong/wanfu-ge.html">万福阁</a></p>',33)])])}const f=e(r,[["render",i]]);export{q as __pageData,f as default};
